#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-22

# Negative-case assertions: after running test-session.sh --negative (plain
# HTTP 403, no rate-limit phrasing), the hook MUST NOT fire and the model
# should continue diagnosing a permission error.
set -euo pipefail

DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
OUT_DIR="${DIR}/../out"
SESSION="${OUT_DIR}/session.jsonl"

if [[ ! -s "${SESSION}" ]]; then
  echo "FAIL: ${SESSION} missing or empty — run test-session.sh --negative first" >&2
  exit 1
fi

FAILURES=0
pass() { echo "PASS: $1"; }
fail() { echo "FAIL: $1" >&2; FAILURES=$((FAILURES + 1)); }

# 1. Hook must not have fired — no banner.
if grep -q "gh-rate-limit-tracker" "${SESSION}"; then
  fail "hook fired on plain 403 (false positive)"
else
  pass "hook did not fire on plain 403"
fi

# 2. The injected 'rate limit' guidance text must not appear.
if grep -qi "rate limit" "${SESSION}"; then
  fail "session output contains 'rate limit' phrase — hook leaked context"
else
  pass "no 'rate limit' phrase in session output"
fi

# 3. Model should be diagnosing the permission error, not stopping.
FINAL_TEXT=""
if command -v jq >/dev/null 2>&1; then
  FINAL_TEXT="$(jq -r 'select(.type == "assistant") | .message.content[]? | select(.type == "text") | .text' "${SESSION}" 2>/dev/null | tail -n 20 || true)"
fi
if [[ -z "${FINAL_TEXT}" ]]; then
  FINAL_TEXT="$(cat "${SESSION}")"
fi
FINAL_LC="$(printf '%s' "${FINAL_TEXT}" | tr '[:upper:]' '[:lower:]')"

if printf '%s' "${FINAL_LC}" | grep -Eq "permission|403|access|not accessible|forbidden"; then
  pass "final assistant message references permission/403/access"
else
  fail "final assistant message does not acknowledge the permission error"
fi

if [[ ${FAILURES} -gt 0 ]]; then
  echo "false-positive.sh: ${FAILURES} assertion(s) failed" >&2
  exit 1
fi
echo "false-positive.sh: all assertions passed"
exit 0
